                                    <div className="text-2xl md:text-4xl font-black text-center text-white leading-tight relative z-10" dangerouslySetInnerHTML={{ __html: currentQ.data.answerText }} />
                                    {currentQ.data.explanation && (
                                        <div className="mt-8 bg-white/5 border border-white/10 p-5 rounded-2xl text-slate-400 text-sm max-w-md text-center leading-relaxed relative z-10">
                                            <span dangerouslySetInnerHTML={{ __html: currentQ.data.explanation }} />
                                        </div>
                                    )}
                                </div>
                            </div>

                            {isFlipped && !currentQ.userAnswer && (
                                <div className="flex gap-4 mt-8 animate-in slide-in-from-bottom-4 duration-300">
                                    <button 
                                        onClick={() => handleAnswer('incorrect')}
                                        className="flex-1 py-4 md:py-6 bg-white border-2 border-rose-100 text-rose-500 rounded-2xl font-black uppercase tracking-widest flex items-center justify-center gap-3 hover:bg-rose-50 transition-all shadow-md active:scale-95"
                                    >
                                        <ThumbsDown size={24} /> Incorrect
                                    </button>
                                    <button 
                                        onClick={() => handleAnswer('correct')}
                                        className="flex-1 py-4 md:py-6 bg-emerald-600 text-white rounded-2xl font-black uppercase tracking-widest flex items-center justify-center gap-3 hover:bg-emerald-500 transition-all shadow-xl shadow-emerald-500/20 active:scale-95"
                                    >
                                        <ThumbsUp size={24} /> I Knew It
                                    </button>
                                </div>
                            )}

                            {currentQ.userAnswer && (
                                <div className={`mt-8 p-6 rounded-2xl flex items-center justify-center gap-4 animate-in zoom-in-95 duration-300 ${currentQ.userAnswer === 'correct' ? 'bg-emerald-50 text-emerald-700' : 'bg-rose-50 text-rose-700'}`}>
                                    {currentQ.userAnswer === 'correct' ? <CheckCircle2 size={24} /> : <AlertTriangle size={24} />}
                                    <span className="font-black uppercase tracking-widest">Logged as {currentQ.userAnswer}</span>
                                </div>
                            )}
                         </div>
                       ) : (
                         <>
                            <div className="flex items-start justify-between gap-4">
                                <div className="text-base md:text-xl font-bold text-slate-900 leading-relaxed tracking-tight">
                                    <span dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
                                </div>
                            </div>

                            {currentQ.data.questionImage && !imgError && (
                                <div 
                                    className="w-full bg-slate-50 rounded-2xl border border-slate-100 p-3 md:p-4 flex justify-center cursor-zoom-in hover:border-blue-200 transition-colors group relative"
                                    onClick={() => setZoomedImage(currentQ.data.questionImage!)}
                                >
                                    <img 
                                    src={currentQ.data.questionImage} 
                                    className="max-h-[30vh] md:max-h-[35vh] object-contain mix-blend-multiply"
                                    onError={() => setImgError(true)}
                                    alt="Question Diagram"
                                    />
                                    <div className="absolute top-4 right-4 bg-white/80 backdrop-blur-sm shadow-sm p-1.5 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
                                        <Maximize2 size={14} className="text-slate-500" />
                                    </div>
                                </div>
                            )}

                            <div className="grid grid-cols-1 gap-2.5">
                                {currentQ.options.map((option, idx) => {
                                    const isSelected = currentQ.userAnswer === option;
                                    const isCorrect = option === currentQ.correctOption;
                                    const showResult = view === 'review' || (mode === 'practice' && !!currentQ.userAnswer);

                                    let btnClass = "border-2 border-slate-50 hover:border-blue-200 hover:bg-slate-50 shadow-sm";
                                    let icon = <div className="w-6 h-6 rounded-md border border-slate-200 flex items-center justify-center text-[10px] font-black text-slate-400 group-hover:border-blue-300 group-hover:text-blue-500">{String.fromCharCode(65 + idx)}</div>;

                                    if (showResult) {
                                    if (isCorrect) {
                                        btnClass = "border-emerald-500 bg-emerald-50 ring-2 ring-emerald-500 shadow-md";
                                        icon = <div className="w-6 h-6 rounded-md bg-emerald-500 text-white flex items-center justify-center"><Check size={14} strokeWidth={3} /></div>;
                                    } else if (isSelected) {
                                        btnClass = "border-red-500 bg-red-50 ring-2 ring-red-500 shadow-md";
                                        icon = <div className="w-6 h-6 rounded-md bg-red-500 text-white flex items-center justify-center"><X size={14} strokeWidth={3} /></div>;
                                    } else {
                                        btnClass = "border-slate-50 opacity-50 grayscale scale-[0.98]";
                                    }
                                    } else if (isSelected) {
                                    btnClass = "border-blue-600 bg-blue-50 ring-2 ring-blue-600 shadow-md";
                                    icon = <div className="w-6 h-6 rounded-md bg-blue-600 text-white flex items-center justify-center font-black">{String.fromCharCode(65 + idx)}</div>;
                                    }

                                    return (
                                    <button
                                        key={idx}
                                        onClick={() => handleAnswer(option)}
                                        disabled={showResult}
                                        className={`w-full p-3 md:p-4 rounded-xl text-left transition-all duration-200 flex items-start gap-4 group ${btnClass}`}
                                    >
                                        <div className="mt-0.5 shrink-0">{icon}</div>
                                        <div className={`text-sm md:text-base font-semibold leading-tight ${isSelected || (showResult && isCorrect) ? 'text-slate-900' : 'text-slate-600'}`}>
                                        <span dangerouslySetInnerHTML={{ __html: option }} />
                                        </div>
                                    </button>
                                    );
                                })}
                            </div>

                            {(view === 'review' || (mode === 'practice' && currentQ.userAnswer && showExplanations)) && (
                                <div className="animate-in fade-in slide-in-from-top-4 duration-500">
                                    <div className={`p-5 md:p-6 rounded-2xl border-l-4 ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-500' : 'bg-rose-50 border-rose-500'}`}>
                                        <div className="flex justify-between items-start mb-2">
                                        <h4 className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest opacity-70">
                                            <Lightbulb size={14} /> Clinical Correlation
                                        </h4>
                                        {currentQ.userAnswer !== currentQ.correctOption && (
                                            <div className="text-[10px] font-black text-rose-600 uppercase bg-white px-2 py-1 rounded border border-rose-200 animate-pulse">
                                            Incorrect Response
                                            </div>
                                        )}
                                        </div>
                                        <div className="prose prose-sm prose-slate max-w-none text-xs md:text-sm leading-relaxed text-slate-700">
                                        {currentQ.data.explanation ? (
                                            <span dangerouslySetInnerHTML={{ __html: currentQ.data.explanation }} />
                                        ) : (
                                            <span className="italic opacity-60">Scientific explanation pending verification. The correct answer identifies the structure as {currentQ.correctOption}.</span>
                                        )}
                                        </div>
                                    </div>
                                </div>
                            )}
                         </>
                       )}
                    </div>
                 </div>

                 <div className="p-3 md:p-4 border-t border-slate-100 bg-white flex justify-between items-center gap-3">
                    <button 
                      onClick={() => setCurrentQIndex(prev => prev - 1)}
                      disabled={currentQIndex === 0}
                      className="flex-1 md:flex-none px-4 md:px-6 py-3 rounded-xl font-bold text-slate-500 hover:bg-slate-100 hover:text-slate-900 disabled:opacity-20 disabled:hover:bg-transparent transition-colors flex items-center justify-center gap-2 text-xs md:text-sm"
                    >
                       <ChevronLeft size={16} /> Prev
                    </button>

                    <div className="hidden sm:flex items-center gap-2">
                       <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">
                          Matrix {currentQIndex + 1}
                       </span>
                       <Dna size={12} className="text-slate-200" />
                       <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">
                          Level {questions.length}
                       </span>
                    </div>

                    {currentQIndex === questions.length - 1 ? (
                      <button 
                        onClick={handleFinishSession}
                        className="flex-1 md:flex-none px-6 md:px-8 py-3 rounded-xl bg-slate-900 text-white font-black hover:bg-blue-600 shadow-lg shadow-blue-500/20 transition-all flex items-center justify-center gap-2 text-xs md:text-sm uppercase tracking-wider"
                      >
                        {view === 'review' ? 'End Session' : 'Submit Matrix'} <CheckCircle2 size={16} />
                      </button>
                    ) : (
                      <button 
                        onClick={() => setCurrentQIndex(prev => prev + 1)}
                        className="flex-1 md:flex-none px-6 md:px-8 py-3 rounded-xl bg-blue-600 text-white font-black hover:bg-blue-700 shadow-lg shadow-blue-500/20 transition-all flex items-center justify-center gap-2 text-xs md:text-sm uppercase tracking-wider"
                      >
                        Next <ChevronRight size={16} />
                      </button>
                    )}
                 </div>
              </div>
           </div>

           <div className="hidden lg:block w-72 shrink-0">
              <QuestionNavigator />
           </div>
        </div>
      </div>
    );
  }

  // Results View
  if (view === 'results') {
    const totalQuestions = questions.length;
    const correctCount = questions.filter(q => q.userAnswer === q.correctOption || q.userAnswer === 'correct').length;
    const incorrectCount = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption && q.userAnswer !== 'correct').length;
    const skippedCount = totalQuestions - correctCount - incorrectCount;
    const score = Math.round((correctCount / totalQuestions) * 100);
    const isPassing = score >= 70;

    return (
      <div className="flex flex-col h-full bg-slate-50 overflow-y-auto">
        <div className="max-w-4xl mx-auto w-full my-8 p-6 animate-in fade-in slide-in-from-bottom-8 duration-700">
           <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-200">
              <div className={`${isPassing ? 'bg-emerald-600' : 'bg-slate-900'} p-12 text-center relative overflow-hidden`}>
                  <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-10"></div>
                  <div className="relative z-10 flex flex-col items-center">
                      <div className="inline-flex p-6 rounded-full bg-white/10 backdrop-blur-md mb-8 shadow-2xl ring-1 ring-white/20">
                        {isPassing ? <Trophy size={64} className="text-white" strokeWidth={1.5} /> : <Target size={64} className="text-white" strokeWidth={1.5} />}
                      </div>
                      <div className="space-y-2 mb-8">
                        <h2 className="text-8xl font-black text-white tracking-tighter leading-none">{score}<span className="text-4xl align-top opacity-60">%</span></h2>
                        <div className="flex items-center justify-center gap-2 opacity-80">
                           <Medal size={16} className="text-white" />
                           <span className="text-sm font-bold text-white uppercase tracking-widest">{isPassing ? 'Certified Excellence' : 'Needs Improvement'}</span>
                        </div>
                      </div>
                  </div>
              </div>

              <div className="grid grid-cols-3 divide-x divide-slate-100 border-b border-slate-100 bg-white">
                 <div className="p-8 text-center hover:bg-slate-50 transition-colors group">
                    <span className="block text-5xl font-black text-emerald-500 mb-2 group-hover:scale-110 transition-transform">{correctCount}</span>
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center justify-center gap-2">
                       <CheckCircle2 size={12} className="text-emerald-500" /> Correct
                    </span>
                 </div>
                 <div className="p-8 text-center hover:bg-slate-50 transition-colors group">
                    <span className="block text-5xl font-black text-rose-500 mb-2 group-hover:scale-110 transition-transform">{incorrectCount}</span>
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center justify-center gap-2">
                       <AlertTriangle size={12} className="text-rose-500" /> Incorrect
                    </span>
                 </div>
                 <div className="p-8 text-center hover:bg-slate-50 transition-colors group">
                    <span className="block text-5xl font-black text-slate-400 mb-2 group-hover:scale-110 transition-transform">{skippedCount}</span>
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center justify-center gap-2">
                       <Hash size={12} /> Skipped
                    </span>
                 </div>
              </div>

              <div className="p-10 bg-slate-50/50 space-y-8">
                  <div className="flex flex-col gap-4">
                      <button 
                        onClick={() => {
                          setView('review');
                          setCurrentQIndex(0);
                        }}
                        className="w-full py-5 rounded-2xl bg-slate-900 text-white font-black text-lg uppercase tracking-widest hover:bg-blue-600 hover:shadow-xl hover:-translate-y-1 transition-all flex items-center justify-center gap-3 shadow-lg shadow-slate-900/10 group"
                      >
                        <Eye size={24} className="group-hover:scale-110 transition-transform" /> Review Questions
                      </button>
                      <button 
                        onClick={() => setView('setup')}
                        className="w-full py-4 rounded-2xl bg-white text-slate-600 font-bold uppercase tracking-widest hover:bg-slate-50 transition-all flex items-center justify-center gap-3 border border-slate-200"
                      >
                        <RotateCcw size={20} /> Retake Assessment
                      </button>
                  </div>
              </div>
           </div>
        </div>
      </div>
    );
  }

  return null;
};

export default Quiz;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Question } from '../types';
import { Shuffle, Filter, ChevronDown, RotateCw, Check, Maximize2, X, ChevronLeft, ChevronRight, Volume2, VolumeX } from 'lucide-react';
import Button from './Button';
import { useSpeech } from '../hooks/useSpeech';

interface FlashcardsProps {
  data: Question[];
}

const Flashcards: React.FC<FlashcardsProps> = ({ data }) => {
  const [deck, setDeck] = useState<Question[]>(data);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [direction, setDirection] = useState<'left' | 'right' | 'none'>('none');
  const [imgError, setImgError] = useState(false);
  const [ansImgError, setAnsImgError] = useState(false);

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [zoomedImage, setZoomedImage] = useState<string | null>(null);

  // Audio Hook
  const { speak, cancel, isSpeaking, speakingId, hasSupport } = useSpeech();

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [data]);

  useEffect(() => {
    let filtered = data;
    if (selectedCategories.length > 0) {
      filtered = data.filter(q => selectedCategories.includes(q.category || 'General'));
    }
    setDeck(filtered);
    setCurrentIndex(0);
    setIsFlipped(false);
    setDirection('none');
  }, [data, selectedCategories]);

  useEffect(() => {
    setImgError(false);
    setAnsImgError(false);
    cancel(); // Stop audio when changing cards
  }, [currentIndex, deck, cancel]);

  const toggleCategory = (cat: string) => {
    setSelectedCategories(prev => 
      prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
    );
  };

  const flipCard = useCallback(() => {
    if (!isAnimating) {
      setIsAnimating(true);
      setIsFlipped(prev => !prev);
      cancel(); // Stop audio on flip
      setTimeout(() => setIsAnimating(false), 300);
    }
  }, [isAnimating, cancel]);

  const nextCard = useCallback(() => {
    if (currentIndex < deck.length - 1) {
      setIsFlipped(false);
      setDirection('right');
      setTimeout(() => {
        setCurrentIndex(prev => prev + 1);
        setDirection('none');
      }, 150);
    }
  }, [currentIndex, deck.length]);

  const prevCard = useCallback(() => {
    if (currentIndex > 0) {
      setIsFlipped(false);
      setDirection('left');
      setTimeout(() => {
        setCurrentIndex(prev => prev - 1);
        setDirection('none');
      }, 150);
    }
  }, [currentIndex]);

  // Keyboard Navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Ignore if user is typing in an input
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;

      switch (e.key) {
        case 'ArrowRight':
          nextCard();
          break;
        case 'ArrowLeft':
          prevCard();
          break;
        case ' ':
        case 'Enter':
          // Only flip if not already handled by a button focus
          if (document.activeElement?.tagName !== 'BUTTON') {
            e.preventDefault(); // Prevent scroll on Space
            flipCard();
          }
          break;
        default:
          break;
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [nextCard, prevCard, flipCard]);

  const handleAudio = (e: React.MouseEvent, text: string, id: string) => {
    e.stopPropagation();
    if (isSpeaking && speakingId === id) {
      cancel();
    } else {
      speak(text, id);
    }
  };

  const currentCard = deck[currentIndex];

  return (
    <div 
      className="h-[calc(100vh-6rem)] flex flex-col max-w-5xl mx-auto w-full px-4 pb-4 focus:outline-none"
      role="application"
      aria-label="Anatomy Flashcards Study Tool"
    >

      {/* --- ZOOM MODAL --- */}
      {zoomedImage && (
        <div 
          className="fixed inset-0 z-[100] bg-black/95 flex items-center justify-center p-4 animate-in fade-in duration-200" 
          onClick={() => setZoomedImage(null)}
          role="dialog"
          aria-modal="true"
          aria-label="Image Preview"
        >
          <button 
            className="absolute top-4 right-4 text-white/70 hover:text-white p-2 transition-colors focus:ring-2 focus:ring-white rounded-lg outline-none" 
            onClick={() => setZoomedImage(null)}
            aria-label="Close image preview"
          >
            <X size={32} />
          </button>
          <img 
            src={zoomedImage} 
            className="max-w-full max-h-full object-contain rounded-md shadow-2xl animate-in zoom-in-95 duration-300" 
            alt="Enlarged view" 
            onClick={(e) => e.stopPropagation()}
          />
        </div>
      )}

      {/* --- TOP CONTROLS (Compact) --- */}
      <div className="flex-none mb-4 flex justify-between items-center gap-3 z-20">
        <div className="flex items-center gap-3">
            <div 
              className="bg-white px-3 py-1.5 rounded-lg border border-slate-200 shadow-sm font-black text-slate-700 text-xs tracking-wider"
              aria-live="polite"
              aria-label={`Card ${currentIndex + 1} of ${deck.length}`}
            >
            {deck.length > 0 ? `${currentIndex + 1} / ${deck.length}` : '0'}
            </div>

            {/* Filter Dropdown */}
            <div className="relative">
                <Button 
                variant="ghost" 
                onClick={() => setIsFilterOpen(!isFilterOpen)}
                className={`flex items-center gap-2 text-[10px] font-bold uppercase tracking-wider rounded-lg border h-8 px-3 transition-all focus:ring-2 focus:ring-blue-400 ${selectedCategories.length > 0 ? 'bg-blue-50 text-blue-600 border-blue-200' : 'bg-white border-slate-200 text-slate-500'}`}
                aria-haspopup="listbox"
                aria-expanded={isFilterOpen}
                aria-label="Filter cards by topic"
                >
                <Filter size={12} />
                {selectedCategories.length > 0 ? `${selectedCategories.length} Topics` : 'Topic'}
                <ChevronDown size={10} className={`transition-transform ${isFilterOpen ? 'rotate-180' : ''}`} />
                </Button>

                {isFilterOpen && (
                <>
                    <div className="fixed inset-0 z-10" onClick={() => setIsFilterOpen(false)}></div>
                    <div 
                      className="absolute left-0 top-full mt-2 w-72 bg-white border border-slate-200 rounded-xl shadow-2xl z-50 flex flex-col max-h-[50vh] focus:outline-none"
                      onClick={(e) => e.stopPropagation()}
                      role="listbox"
                      aria-multiselectable="true"
                    >
                    <div className="p-3 bg-slate-50 border-b border-slate-100 flex justify-between items-center rounded-t-xl">
                        <span className="text-xs font-bold text-slate-500 uppercase">Select Chapters</span>
                        <button 
                          onClick={() => setSelectedCategories([])} 
                          className="text-[10px] font-bold text-red-500 hover:text-red-700 focus:outline-none focus:underline"
                          aria-label="Clear all filters"
                        >
                          Reset All
                        </button>
                    </div>
                    <div className="overflow-y-auto p-2 custom-scrollbar">
                        {categories.map(cat => (
                        <label 
                          key={cat} 
                          className="flex items-center gap-3 p-2.5 hover:bg-slate-50 rounded-lg cursor-pointer transition-colors group"
                        >
                            <div className={`w-4 h-4 rounded border-2 flex items-center justify-center transition-colors group-focus-within:ring-2 group-focus-within:ring-blue-400 ${selectedCategories.includes(cat) ? 'bg-blue-600 border-blue-600' : 'border-slate-300 bg-white'}`}>
                            {selectedCategories.includes(cat) && <Check size={10} className="text-white" />}
                            </div>
                            <span className="text-xs font-bold text-slate-700 leading-tight">{cat}</span>
                            <input 
                            type="checkbox" 
                            className="hidden"
                            checked={selectedCategories.includes(cat)}
                            onChange={() => toggleCategory(cat)}
                            role="option"
                            aria-selected={selectedCategories.includes(cat)}
                            />
                        </label>
                        ))}
                    </div>
                    </div>
                </>
                )}
            </div>
        </div>

        <Button 
            variant="ghost" 
            onClick={() => {
              const shuffled = [...deck].sort(() => Math.random() - 0.5);
              setDeck(shuffled);
              setCurrentIndex(0);
              setIsFlipped(false);
              setDirection('none');
            }} 
            className="h-8 px-3 text-[10px] font-bold text-slate-500 bg-white border border-slate-200 rounded-lg uppercase tracking-wider hover:text-blue-600 hover:border-blue-200 focus:ring-2 focus:ring-blue-400"
            aria-label="Shuffle deck"
        >
            <Shuffle size={12} className="mr-1" /> Shuffle
        </Button>
      </div>

      {/* --- THE CARD (Flexible Height) --- */}
      <div className="flex-1 min-h-0 relative perspective-1000 z-10 group mb-4">
        {deck.length > 0 && currentCard ? (
            <div 
                key={currentCard.id}
                className={`w-full h-full relative transform-style-3d transition-all duration-500 ease-in-out cursor-pointer focus:outline-none focus:ring-4 focus:ring-blue-400/20 rounded-3xl ${isFlipped ? 'rotate-y-180' : ''} ${direction === 'right' ? 'animate-slide-in-right' : direction === 'left' ? 'animate-slide-in-left' : ''}`}
                onClick={flipCard}
                tabIndex={0}
                onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); flipCard(); } }}
                role="button"
                aria-label={`Flashcard: ${isFlipped ? 'Showing Answer' : 'Showing Question'}. Click to flip.`}
                aria-live="polite"
            >

            {/* FRONT (Question) */}
            <div 
              className="absolute inset-0 w-full h-full bg-white rounded-3xl shadow-[0_4px_20px_rgb(0,0,0,0.05)] border-2 border-slate-100 backface-hidden flex flex-col overflow-hidden"
              aria-hidden={isFlipped}
            >
              <div className="px-6 pt-5 flex justify-between items-start flex-none">
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] bg-slate-50 px-3 py-1 rounded-full border border-slate-100">
                  Question
                </span>

                {hasSupport && (
                  <button 
                    onClick={(e) => handleAudio(e, currentCard.questionText, currentCard.id + 'q')}
                    className={`p-2 rounded-full transition-colors focus:ring-2 focus:ring-red-400 ${isSpeaking && speakingId === currentCard.id + 'q' ? 'bg-red-100 text-red-600' : 'bg-slate-50 text-slate-400 hover:bg-slate-100 hover:text-slate-900'}`}
                    title="Read Question"
                    aria-label={isSpeaking && speakingId === currentCard.id + 'q' ? "Stop reading question" : "Read question text out loud"}
                  >
                    {isSpeaking && speakingId === currentCard.id + 'q' ? <VolumeX size={16} /> : <Volume2 size={16} />}
                  </button>
                )}
              </div>

              <div className="flex-1 p-6 flex flex-col items-center justify-center overflow-y-auto custom-scrollbar">
                {currentCard.questionImage && !imgError && (
                  <button 
