import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Question } from '../types';
import { Shuffle, Filter, ChevronDown, RotateCw, Check, Maximize2, X, ChevronLeft, ChevronRight, Volume2, VolumeX } from 'lucide-react';
import Button from './Button';
import { useSpeech } from '../hooks/useSpeech';

interface FlashcardsProps {
  data: Question[];
}

const Flashcards: React.FC<FlashcardsProps> = ({ data }) => {
  const [deck, setDeck] = useState<Question[]>(data);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [direction, setDirection] = useState<'left' | 'right' | 'none'>('none');
  const [imgError, setImgError] = useState(false);
  const [ansImgError, setAnsImgError] = useState(false);

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [zoomedImage, setZoomedImage] = useState<string | null>(null);

  // Audio Hook
  const { speak, cancel, isSpeaking, speakingId, hasSupport } = useSpeech();

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [data]);

  useEffect(() => {
    let filtered = data;
    if (selectedCategories.length > 0) {
      filtered = data.filter(q => selectedCategories.includes(q.category || 'General'));
    }
    setDeck(filtered);
    setCurrentIndex(0);
    setIsFlipped(false);
    setDirection('none');
  }, [data, selectedCategories]);

  useEffect(() => {
    setImgError(false);
    setAnsImgError(false);
    cancel(); // Stop audio when changing cards
  }, [currentIndex, deck, cancel]);

  const toggleCategory = (cat: string) => {
    setSelectedCategories(prev => 
      prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
    );
  };

  const flipCard = useCallback(() => {
    if (!isAnimating) {
      setIsAnimating(true);
      setIsFlipped(prev => !prev);
      cancel(); // Stop audio on flip
      setTimeout(() => setIsAnimating(false), 300);
    }
  }, [isAnimating, cancel]);

  const nextCard = useCallback(() => {
    if (currentIndex < deck.length - 1) {
      setIsFlipped(false);
      setDirection('right');
      setTimeout(() => {
        setCurrentIndex(prev => prev + 1);
        setDirection('none');
      }, 150);
    }
  }, [currentIndex, deck.length]);

  const prevCard = useCallback(() => {
    if (currentIndex > 0) {
      setIsFlipped(false);
      setDirection('left');
      setTimeout(() => {
        setCurrentIndex(prev => prev - 1);
        setDirection('none');
      }, 150);
    }
  }, [currentIndex]);

  // Keyboard Navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Ignore if user is typing in an input
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;

      switch (e.key) {
        case 'ArrowRight':
          nextCard();
          break;
        case 'ArrowLeft':
          prevCard();
          break;
        case ' ':
        case 'Enter':
          // Only flip if not already handled by a button focus
          if (document.activeElement?.tagName !== 'BUTTON') {
            e.preventDefault(); // Prevent scroll on Space
            flipCard();
          }
          break;
        default:
          break;
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [nextCard, prevCard, flipCard]);

  const handleAudio = (e: React.MouseEvent, text: string, id: string) => {
    e.stopPropagation();
    if (isSpeaking && speakingId === id) {
      cancel();
    } else {
      speak(text, id);
    }
  };

  const currentCard = deck[currentIndex];

  return (
    <div 
      className="flex flex-col max-w-5xl mx-auto w-full px-3 md:px-4 h-full focus:outline-none"
      role="application"
      aria-label="Anatomy Flashcards Study Tool"
    >

      {/* --- ZOOM MODAL --- */}
      {zoomedImage && (
        <div 
          className="fixed inset-0 z-[100] bg-black/95 flex items-center justify-center p-2 md:p-4 animate-in fade-in duration-200" 
          onClick={() => setZoomedImage(null)}
          role="dialog"
          aria-modal="true"
          aria-label="Image Preview"
        >
          <button 
            className="absolute top-4 right-4 text-white/70 hover:text-white p-2 transition-colors focus:ring-2 focus:ring-white rounded-lg outline-none" 
            onClick={() => setZoomedImage(null)}
            aria-label="Close image preview"
          >
            <X size={28} />
          </button>
          <img 
            src={zoomedImage} 
            className="max-w-full max-h-full object-contain rounded-md shadow-2xl animate-in zoom-in-95 duration-300" 
            alt="Enlarged view" 
            onClick={(e) => e.stopPropagation()}
          />
        </div>
      )}

      {/* --- TOP CONTROLS (Compact) --- */}
      <div className="flex-none mb-2 md:mb-4 flex justify-between items-center gap-2 md:gap-3 z-20">
        <div className="flex items-center gap-2 md:gap-3 flex-1 min-w-0">
            <div 
              className="bg-white px-2.5 py-1.5 rounded-lg border border-slate-200 shadow-sm font-black text-slate-700 text-[10px] md:text-xs tracking-wider whitespace-nowrap"
              aria-live="polite"
              aria-label={`Card ${currentIndex + 1} of ${deck.length}`}
            >
            {deck.length > 0 ? `${currentIndex + 1} / ${deck.length}` : '0'}
            </div>

            {/* Filter Dropdown */}
            <div className="relative flex-1 min-w-0">
                <Button 
                variant="ghost" 
                onClick={() => setIsFilterOpen(!isFilterOpen)}
                className={`flex items-center gap-1 md:gap-2 text-[10px] font-bold uppercase tracking-wider rounded-lg border h-8 px-2 md:px-3 transition-all focus:ring-2 focus:ring-blue-400 w-full md:w-auto justify-between md:justify-start ${selectedCategories.length > 0 ? 'bg-blue-50 text-blue-600 border-blue-200' : 'bg-white border-slate-200 text-slate-500'}`}
                aria-haspopup="listbox"
                aria-expanded={isFilterOpen}
                aria-label="Filter cards by topic"
                >
                <div className="flex items-center gap-2 truncate">
                    <Filter size={12} className="shrink-0" />
