            }} 
            className="h-8 px-2 md:px-3 text-[10px] font-bold text-slate-500 bg-white border border-slate-200 rounded-lg uppercase tracking-wider hover:text-blue-600 hover:border-blue-200 focus:ring-2 focus:ring-blue-400 shrink-0"
            aria-label="Shuffle deck"
        >
