        </Button>
      </div>

      {/* --- THE CARD (Flex Filling) --- */}
      <div className="flex-1 min-h-0 relative perspective-1000 z-10 group mb-4">
        {deck.length > 0 && currentCard ? (
            <div 
                key={currentCard.id}
                className={`w-full h-full relative transform-style-3d transition-all duration-500 ease-in-out cursor-pointer focus:outline-none focus:ring-4 focus:ring-blue-400/20 rounded-[2rem] ${isFlipped ? 'rotate-y-180' : ''} ${direction === 'right' ? 'animate-slide-in-right' : direction === 'left' ? 'animate-slide-in-left' : ''}`}
                onClick={flipCard}
                tabIndex={0}
                onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); flipCard(); } }}
                role="button"
                aria-label={`Flashcard: ${isFlipped ? 'Showing Answer' : 'Showing Question'}. Click to flip.`}
                aria-live="polite"
            >

            {/* FRONT (Question) */}
            <div 
              className="absolute inset-0 w-full h-full bg-white rounded-[2rem] shadow-[0_4px_20px_rgb(0,0,0,0.05)] border-2 border-slate-100 backface-hidden flex flex-col overflow-hidden"
              aria-hidden={isFlipped}
            >
              <div className="px-4 py-3 md:px-6 md:pt-5 flex justify-between items-start flex-none">
                <span className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] bg-slate-50 px-2.5 py-1 rounded-full border border-slate-100">
                  Question
