                {hasSupport && (
                  <button 
                    onClick={(e) => handleAudio(e, currentCard.questionText, currentCard.id + 'q')}
                    className={`p-1.5 md:p-2 rounded-full transition-colors focus:ring-2 focus:ring-red-400 ${isSpeaking && speakingId === currentCard.id + 'q' ? 'bg-red-100 text-red-600' : 'bg-slate-50 text-slate-400 hover:bg-slate-100 hover:text-slate-900'}`}
                    title="Read Question"
                    aria-label={isSpeaking && speakingId === currentCard.id + 'q' ? "Stop reading question" : "Read question text out loud"}
                  >
                    {isSpeaking && speakingId === currentCard.id + 'q' ? <VolumeX size={14} className="md:w-4 md:h-4" /> : <Volume2 size={14} className="md:w-4 md:h-4" />}
                  </button>
                )}
              </div>

              <div className="flex-1 p-4 md:p-6 flex flex-col items-center justify-center overflow-y-auto custom-scrollbar">
                {currentCard.questionImage && !imgError && (
                  <button 
                    className="mb-4 md:mb-6 flex-none bg-slate-50 p-1.5 md:p-2 rounded-xl border border-slate-100 relative group/img hover:border-blue-300 transition-colors cursor-zoom-in max-h-[35%] md:max-h-[45%] outline-none focus:ring-2 focus:ring-blue-400"
                    onClick={(e) => { e.stopPropagation(); setZoomedImage(currentCard.questionImage!); }}
                    aria-label="Zoom in on question diagram"
                  >
                    <img 
                      src={currentCard.questionImage} 
                      className="max-h-full w-auto object-contain rounded-lg mix-blend-multiply"
