            <div className="bg-slate-900 p-5 md:p-8 flex items-center justify-between border-b border-slate-800">
              <div>
                <h1 className="text-xl md:text-3xl font-black text-white tracking-tight flex items-center gap-3">
                  <LayoutGrid className="text-blue-500 md:w-8 md:h-8" size={24} /> 
