import React, { useState, useMemo, useEffect } from 'react';
import { Question } from '../types';
import { 
  Search, Download, Upload, ShieldCheck, Database, 
  Filter, ArrowUpDown, X, ChevronDown, Check, Highlighter,
  Volume2, VolumeX
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

interface QuestionListProps {
  data: Question[];
  onExport: () => void;
  onImport: (e: React.ChangeEvent<HTMLInputElement>) => void;
}

const ITEMS_PER_PAGE = 20;

const QuestionList: React.FC<QuestionListProps> = ({ data, onExport, onImport }) => {
  const [search, setSearch] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [selectedCategory, setSelectedCategory] = useState<string>('All');
  const [sortOrder, setSortOrder] = useState<'default' | 'asc' | 'desc'>('default');
  const [isFilterMenuOpen, setIsFilterMenuOpen] = useState(false);

  // Audio Hook
  const { speak, cancel, isSpeaking, speakingId, hasSupport } = useSpeech();

  // Helper to remove HTML tags for searching and sorting (still used for search)
  const stripHtml = (html: string) => {
    const tmp = document.createElement("DIV");
    tmp.innerHTML = html;
    return tmp.textContent || tmp.innerText || "";
  };

  // Helper to escape regex characters
  const escapeRegExp = (string: string) => {
    return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  };

  // Helper to highlight matched terms
  const highlightText = (text: string, query: string) => {
    if (!query.trim()) return text;

    const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
    let highlightedText = text;

    terms.forEach(term => {
      const regex = new RegExp(`(${escapeRegExp(term)})(?![^<]*>)`, 'gi');
      highlightedText = highlightedText.replace(regex, '<mark class="bg-yellow-300 text-slate-900 rounded-sm px-0.5 font-bold">$1</mark>');
    });

    return highlightedText;
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'Uncategorized'));
    return ['All', ...Array.from(cats).sort()];
  }, [data]);

  const processedData = useMemo(() => {
    let result = data;

    if (selectedCategory !== 'All') {
      result = result.filter(q => (q.category || 'Uncategorized') === selectedCategory);
    }

    if (search.trim()) {
      const terms = search.toLowerCase().split(/\s+/).filter(Boolean);

      result = result.filter(q => {
        const qText = stripHtml(q.questionText).toLowerCase();
        const aText = stripHtml(q.answerText).toLowerCase();
        return terms.every(term => qText.includes(term) || aText.includes(term));
      });
    }

    if (sortOrder === 'asc') {
      result = [...result].sort((a, b) => stripHtml(a.questionText).localeCompare(stripHtml(b.questionText)));
    } else if (sortOrder === 'desc') {
      result = [...result].sort((a, b) => stripHtml(b.questionText).localeCompare(stripHtml(a.questionText)));
    }

    return result;
  }, [data, selectedCategory, search, sortOrder]);

  useEffect(() => {
    setCurrentPage(1);
  }, [search, selectedCategory, sortOrder]);

  useEffect(() => {
    return () => cancel();
  }, [currentPage, cancel]);

  const handleAudio = (e: React.MouseEvent, text: string, id: string) => {
    e.stopPropagation();
    if (isSpeaking && speakingId === id) {
      cancel();
    } else {
      speak(text, id);
    }
  };

  const totalPages = Math.ceil(processedData.length / ITEMS_PER_PAGE);
  const currentData = processedData.slice(
    (currentPage - 1) * ITEMS_PER_PAGE,
    currentPage * ITEMS_PER_PAGE
  );

  const handlePageChange = (newPage: number) => {
    cancel();
    setCurrentPage(newPage);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="max-w-7xl mx-auto w-full px-3 md:px-4 pb-32">
      <div className="bg-white rounded-3xl p-4 md:p-8 border border-slate-200 shadow-xl overflow-hidden relative group mb-4">
        <div className="absolute top-0 right-0 p-4 opacity-5 pointer-events-none">
          <Database size={100} className="md:w-[200px] md:h-[200px]" />
        </div>

        <div className="flex flex-col md:flex-row justify-between gap-4 md:gap-6 relative z-10">
          <div className="space-y-1 md:space-y-2">
            <h2 className="text-xl md:text-3xl font-black text-slate-900 tracking-tight">
              Knowledge <span className="text-blue-600">Index</span>
            </h2>
            <div className="flex flex-wrap items-center gap-3 md:gap-4 text-[10px] md:text-xs font-bold text-slate-500 uppercase tracking-widest">
              <span className="flex items-center gap-1"><Database size={14} className="text-blue-500" /> {data.length.toLocaleString()} Total</span>
              <span className="flex items-center gap-1"><Highlighter size={14} className="text-amber-500" /> {processedData.length.toLocaleString()} Found</span>
            </div>
          </div>

          <div className="flex gap-2 w-full md:w-auto">
            <button 
              onClick={onExport}
              className="flex-1 md:flex-none flex items-center justify-center gap-2 px-3 py-2 md:px-4 md:py-3 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-xl font-bold text-[10px] md:text-xs uppercase tracking-wider transition-all"
            >
              <Download size={14} className="md:w-4 md:h-4" /> Backup
            </button>
            <label className="flex-1 md:flex-none flex items-center justify-center gap-2 px-3 py-2 md:px-4 md:py-3 bg-slate-900 hover:bg-slate-800 text-white rounded-xl font-bold text-[10px] md:text-xs uppercase tracking-wider cursor-pointer transition-all shadow-lg">
              <Upload size={14} className="md:w-4 md:h-4" /> Restore
              <input type="file" className="hidden" accept=".json" onChange={onImport} />
            </label>
          </div>
        </div>
      </div>

      <div className="sticky top-0 pt-2 pb-2 z-30 bg-slate-50/95 backdrop-blur-sm space-y-2 transition-all">
        <div className={`relative shadow-md rounded-2xl transition-all ${search ? 'ring-2 ring-blue-400' : ''}`}>
          <input 
            type="text" 
            placeholder="Search definitions, muscles..." 
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-10 pr-10 md:pl-12 md:pr-12 py-3 md:py-3.5 rounded-2xl border-2 border-slate-200 bg-white text-sm md:text-base font-semibold text-slate-800 focus:border-blue-500 focus:ring-0 outline-none transition-all placeholder:text-slate-400"
          />
          <Search className={`absolute left-3 md:left-4 top-1/2 -translate-y-1/2 transition-colors ${search ? 'text-blue-500' : 'text-slate-400'}`} size={18} />
          {search && (
            <button onClick={() => setSearch('')} className="absolute right-3 md:right-4 top-1/2 -translate-y-1/2 p-1 bg-slate-100 hover:bg-red-100 text-slate-400 hover:text-red-500 rounded-full transition-colors">
              <X size={14} />
            </button>
          )}
        </div>

        <div className="flex gap-2">
          <div className="relative flex-1">
            <button 
              onClick={() => setIsFilterMenuOpen(!isFilterMenuOpen)}
              className={`w-full flex items-center justify-between px-3 py-2.5 md:px-4 md:py-3 bg-white border rounded-xl font-bold text-xs md:text-sm shadow-sm transition-all ${selectedCategory !== 'All' ? 'border-blue-300 text-blue-700 bg-blue-50' : 'border-slate-200 text-slate-700 hover:border-blue-300'}`}
            >
              <span className="flex items-center gap-2 truncate">
                <Filter size={14} className={selectedCategory !== 'All' ? "text-blue-600" : "text-blue-500"} />
                <span className="truncate">{selectedCategory}</span>
              </span>
              <ChevronDown size={14} className={`text-slate-400 transition-transform ${isFilterMenuOpen ? 'rotate-180' : ''}`} />
            </button>

            {isFilterMenuOpen && (
              <>
                <div className="fixed inset-0 z-10" onClick={() => setIsFilterMenuOpen(false)}></div>
                <div className="absolute top-full left-0 mt-2 w-full bg-white border border-slate-200 rounded-xl shadow-2xl z-20 max-h-[60vh] overflow-y-auto custom-scrollbar p-2">
                  {categories.map(cat => (
                    <button
                      key={cat}
                      onClick={() => { setSelectedCategory(cat); setIsFilterMenuOpen(false); }}
                      className={`w-full text-left px-3 py-2.5 rounded-lg text-xs md:text-sm font-bold transition-colors flex items-center justify-between ${selectedCategory === cat ? 'bg-blue-50 text-blue-700' : 'text-slate-600 hover:bg-slate-50'}`}
                    >
                      {cat}
                      {selectedCategory === cat && <Check size={14} />}
                    </button>
                  ))}
                </div>
              </>
            )}
          </div>

          <button 
            onClick={() => setSortOrder(prev => prev === 'default' ? 'asc' : prev === 'asc' ? 'desc' : 'default')}
            className={`flex items-center justify-center gap-2 px-3 py-2.5 md:px-4 md:py-3 rounded-xl font-bold text-xs md:text-sm border transition-all shadow-sm shrink-0 ${sortOrder !== 'default' ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
          >
            <ArrowUpDown size={14} />
            <span className="hidden md:inline">{sortOrder === 'default' ? 'Sort' : sortOrder === 'asc' ? 'A-Z' : 'Z-A'}</span>
          </button>
        </div>
      </div>

      <div className="space-y-3 md:space-y-4">
        {processedData.length === 0 ? (
          <div className="text-center py-20 bg-white rounded-3xl border-2 border-dashed border-slate-300">
            <Search size={48} className="mx-auto text-slate-200 mb-4" />
            <p className="text-slate-400 font-bold">No results found.</p>
          </div>
        ) : (
          currentData.map((q) => (
            <div key={q.id} className="bg-white rounded-2xl border border-slate-200 shadow-sm hover:shadow-md transition-all duration-300 overflow-hidden flex flex-col md:flex-row group">
              {q.questionImage && (
                <div className="w-full md:w-48 h-40 md:h-auto bg-slate-50 border-b md:border-b-0 md:border-r border-slate-100 flex items-center justify-center p-4 shrink-0">
                  <img src={q.questionImage} alt="Diagram" className="max-w-full max-h-full object-contain rounded-lg mix-blend-multiply" loading="lazy" />
                </div>
              )}

              <div className="p-4 md:p-6 flex-1 flex flex-col gap-2 md:gap-3">
                <div className="flex items-start justify-between gap-4">
                  <div className="flex items-center gap-2">
                    <span className="text-[9px] md:text-[10px] font-black uppercase text-blue-500 bg-blue-50 px-2 py-1 rounded border border-blue-100 tracking-wider">
                        {q.category || 'General'}
                    </span>
                    {hasSupport && (
                        <button 
                          onClick={(e) => handleAudio(e, `Question: ${q.questionText}. Answer: ${q.answerText}. ${q.explanation ? 'Explanation: ' + q.explanation : ''}`, q.id)}
                          className={`p-1.5 md:p-2 rounded-full transition-all ${isSpeaking && speakingId === q.id ? 'bg-red-100 text-red-600 ring-2 ring-red-200' : 'bg-slate-50 text-slate-400 hover:bg-blue-50 hover:text-blue-600 shadow-sm'}`}
                          title="Read Question & Answer"
                        >
                          {isSpeaking && speakingId === q.id ? <VolumeX size={14} /> : <Volume2 size={14} />}
                        </button>
                    )}
                  </div>
                </div>

                <div>
                  <h3 
                    className="text-sm md:text-lg font-bold text-slate-900 leading-snug mb-1 md:mb-2"
                    dangerouslySetInnerHTML={{ __html: highlightText(q.questionText, search) }}
                  />
                  <div className="pl-3 md:pl-4 border-l-4 border-blue-500 py-1 transition-all group-hover:border-blue-600">
                    <p 
                      className="text-xs md:text-base font-medium text-slate-600 leading-relaxed"
                      dangerouslySetInnerHTML={{ __html: highlightText(q.answerText, search) }}
                    />
                  </div>
                </div>

                {q.explanation && (
                  <div className="mt-1 md:mt-2 bg-slate-50 p-2 md:p-3 rounded-lg border border-slate-100 text-[10px] md:text-sm text-slate-500">
                    <span className="font-bold text-slate-400 text-[9px] md:text-[10px] uppercase mr-2">Note:</span>
                    <span dangerouslySetInnerHTML={{ __html: highlightText(q.explanation, search) }} />
                  </div>
                )}
              </div>
            </div>
          ))
        )}
      </div>

      {totalPages > 1 && (
        <div className="flex justify-center items-center gap-2 md:gap-3 pt-4 md:pt-6">
          <button 
            onClick={() => handlePageChange(currentPage - 1)}
            disabled={currentPage === 1}
            className="px-3 py-1.5 md:px-4 md:py-2 rounded-xl bg-white border border-slate-200 text-slate-600 font-bold disabled:opacity-50 disabled:cursor-not-allowed hover:bg-slate-50 transition-colors shadow-sm text-xs md:text-sm"
          >
            Prev
          </button>

          <div className="px-3 py-1.5 md:px-4 md:py-2 bg-slate-800 text-white rounded-xl font-bold text-xs md:text-sm shadow-lg">
            Page {currentPage} / {totalPages}
          </div>

          <button 
            onClick={() => handlePageChange(currentPage + 1)}
            disabled={currentPage === totalPages}
            className="px-3 py-1.5 md:px-4 md:py-2 rounded-xl bg-white border border-slate-200 text-slate-600 font-bold disabled:opacity-50 disabled:cursor-not-allowed hover:bg-slate-50 transition-colors shadow-sm text-xs md:text-sm"
          >
            Next
          </button>
        </div>
      )}
    </div>
  );
};

